   169	        if (c.getClientSecret() != null) {
   170	            node.put("ClientSecret", c.getClientSecret());
   171	        }
   172	        node.put("GenerateSecret", c.isGenerateSecret());
   173	        node.put("AllowedOAuthFlowsUserPoolClient", c.isAllowedOAuthFlowsUserPoolClient());
   174	        ArrayNode flows = node.putArray("AllowedOAuthFlows");
   175	        c.getAllowedOAuthFlows().forEach(flows::add);
   176	        ArrayNode scopes = node.putArray("AllowedOAuthScopes");
   177	        c.getAllowedOAuthScopes().forEach(scopes::add);
   178	        node.put("CreationDate", c.getCreationDate());
   179	        node.put("LastModifiedDate", c.getLastModifiedDate());
   180	        return node;
