   183	    private ObjectNode resourceServerToNode(ResourceServer server) {
   184	        ObjectNode node = objectMapper.createObjectNode();
   185	        node.put("UserPoolId", server.getUserPoolId());
   186	        node.put("Identifier", server.getIdentifier());
   187	        node.put("Name", server.getName());
   188	        node.put("CreationDate", server.getCreationDate());
   189	        node.put("LastModifiedDate", server.getLastModifiedDate());
   190	        ArrayNode scopes = node.putArray("Scopes");
   191	        for (ResourceServerScope scope : server.getScopes()) {
   192	            ObjectNode item = scopes.addObject();
   193	            item.put("ScopeName", scope.getScopeName());
   194	            if (scope.getScopeDescription() != null) {
   195	                item.put("ScopeDescription", scope.getScopeDescription());
   196	            }
   197	        }
   198	        return node;
