   201	    private List<ResourceServerScope> parseScopes(JsonNode scopesNode) {
   202	        if (scopesNode == null || !scopesNode.isArray()) {
   203	            return List.of();
   204	        }
   205	
   206	        List<ResourceServerScope> scopes = new java.util.ArrayList<>();
   207	        scopesNode.forEach(item -> {
   208	            ResourceServerScope scope = new ResourceServerScope();
   209	            scope.setScopeName(item.path("ScopeName").asText());
   210	            scope.setScopeDescription(item.path("ScopeDescription").asText(null));
   211	            scopes.add(scope);
   212	        });
   213	        return scopes;
   214	    }
