   374	    private static JsonNode decodeJwtPart(String token, int partIndex) throws Exception {
   375	        String[] parts = token.split("\\.");
   376	        assertEquals(3, parts.length);
   377	        return OBJECT_MAPPER.readTree(Base64.getUrlDecoder().decode(padBase64(parts[partIndex])));
