   380	    private static boolean verifyJwtSignature(String token, JsonNode jwk) throws Exception {
   381	        String[] parts = token.split("\\.");
   382	        assertEquals(3, parts.length);
   383	
   384	        BigInteger modulus = new BigInteger(1, Base64.getUrlDecoder().decode(padBase64(jwk.path("n").asText())));
   385	        BigInteger exponent = new BigInteger(1, Base64.getUrlDecoder().decode(padBase64(jwk.path("e").asText())));
   386	        RSAPublicKeySpec keySpec = new RSAPublicKeySpec(modulus, exponent);
   387	        PublicKey publicKey = KeyFactory.getInstance("RSA").generatePublic(keySpec);
   388	
   389	        Signature signature = Signature.getInstance("SHA256withRSA");
   390	        signature.initVerify(publicKey);
   391	        signature.update((parts[0] + "." + parts[1]).getBytes(StandardCharsets.UTF_8));
   392	        return signature.verify(Base64.getUrlDecoder().decode(padBase64(parts[2])));
   393	    }
